import{_ as e,a as t,b as i,c as o}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as n,o as d,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Dodawanie kanału Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/yandex.md","filePath":"pl-PL/upload/yandex.md","lastUpdated":1781962217000}'),s={name:"pl-PL/upload/yandex.md"};function c(p,a,k,h,u,z){return d(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="dodawanie-kanału-yandex" tabindex="-1">Dodawanie kanału Yandex <a class="header-anchor" href="#dodawanie-kanału-yandex" aria-label="Permalink to &quot;Dodawanie kanału Yandex&quot;">​</a></h1><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Dlaczego jest potrzebne</th></tr></thead><tbody><tr><td>Konto Yandex</td><td>Do logowania i autoryzacji Yandex Disk</td></tr><tr><td>Aplikacja OAuth Yandex</td><td>Do wygenerowania <code>Client ID</code> i <code>Client Secret</code></td></tr><tr><td>Domena ImgBed</td><td>Do URI przekierowania OAuth</td></tr><tr><td>Dostępne miejsce Yandex Disk</td><td>Właściwe miejsce przechowywania plików</td></tr></tbody></table><h2 id="konfiguracja" tabindex="-1">Konfiguracja <a class="header-anchor" href="#konfiguracja" aria-label="Permalink to &quot;Konfiguracja&quot;">​</a></h2><h3 id="krok-1-utworz-aplikacje-oauth-yandex" tabindex="-1">Krok 1: Utwórz aplikację OAuth Yandex <a class="header-anchor" href="#krok-1-utworz-aplikacje-oauth-yandex" aria-label="Permalink to &quot;Krok 1: Utwórz aplikację OAuth Yandex&quot;">​</a></h3><ol><li>Otwórz stronę tworzenia aplikacji OAuth Yandex:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Jeśli zostaniesz przekierowany do logowania, najpierw zaloguj się kontem Yandex.</li><li>Utwórz nową aplikację.</li><li>Nadaj aplikacji rozpoznawalną nazwę, np. <code>imgbed-yandex</code>.</li><li>Znajdź ustawienia callback lub redirect URL.</li><li>Wpisz:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="krok-2-potwierdz-uprawnienia" tabindex="-1">Krok 2: Potwierdź uprawnienia <a class="header-anchor" href="#krok-2-potwierdz-uprawnienia" aria-label="Permalink to &quot;Krok 2: Potwierdź uprawnienia&quot;">​</a></h3><p>Dla obecnej integracji Yandex w ImgBed zachowaj te cztery uprawnienia pod <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Uprawnienie</th><th>Cel</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Pozwala ImgBed zapisywać pliki w folderze aplikacji</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Czyta pliki i linki pobierania</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Przesyła pliki, tworzy katalogi i usuwa pliki</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Czyta limit dysku i użyte miejsce</td></tr></tbody></table><p>Jeśli pod <code>Yandex ID API</code> widzisz też te uprawnienia, są opcjonalne:</p><table tabindex="0"><thead><tr><th>Tekst uprawnienia</th><th>Rekomendacja</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Opcjonalne</td></tr><tr><td><code>Access to email address</code></td><td>Opcjonalne</td></tr></tbody></table><p>Upload, pobieranie, usuwanie i limity zależą głównie od czterech uprawnień <code>Yandex.Disk REST API</code> powyżej.</p><p><img src="'+e+'" alt="Konfiguracja uprawnień Yandex Disk" loading="lazy"></p><h3 id="krok-3-skopiuj-dane-aplikacji" tabindex="-1">Krok 3: Skopiuj dane aplikacji <a class="header-anchor" href="#krok-3-skopiuj-dane-aplikacji" aria-label="Permalink to &quot;Krok 3: Skopiuj dane aplikacji&quot;">​</a></h3><p>Po utworzeniu aplikacji skopiuj:</p><table tabindex="0"><thead><tr><th>Pole Yandex</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Zapisz Client ID i Secret" loading="lazy"></p><h3 id="krok-4-wypełnij-kanał-yandex" tabindex="-1">Krok 4: Wypełnij kanał Yandex <a class="header-anchor" href="#krok-4-wypełnij-kanał-yandex" aria-label="Permalink to &quot;Krok 4: Wypełnij kanał Yandex&quot;">​</a></h3><p>W Ustawieniach przesyłania wybierz <code>Yandex</code> i wypełnij:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co wpisać</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa, np. <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> aplikacji Yandex</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> aplikacji Yandex</td></tr><tr><td>Refresh Token</td><td>Na razie zostaw puste</td></tr><tr><td>Katalog główny</td><td>Opcjonalnie. Domyślnie <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Edycja konfiguracji kanału" loading="lazy"></p><h3 id="krok-5-pobierz-refresh-token" tabindex="-1">Krok 5: Pobierz Refresh Token <a class="header-anchor" href="#krok-5-pobierz-refresh-token" aria-label="Permalink to &quot;Krok 5: Pobierz Refresh Token&quot;">​</a></h3><ol><li>W ImgBed kliknij <code>Get Token</code>.</li><li>Zaloguj się na konto Yandex, które chcesz podłączyć.</li><li>Zatwierdź autoryzację.</li><li>Strona callback pokaże <code>Refresh Token</code>.</li><li>Skopiuj go.</li><li>Wróć do ImgBed i wklej go w polu <code>Refresh Token</code>.</li></ol><p><img src="'+o+`" alt="Kopiowanie Refresh Token po autoryzacji" loading="lazy"></p><h3 id="krok-6-zapisz-kanał" tabindex="-1">Krok 6: Zapisz kanał <a class="header-anchor" href="#krok-6-zapisz-kanał" aria-label="Permalink to &quot;Krok 6: Zapisz kanał&quot;">​</a></h3><p>Po wypełnieniu wszystkich pól zapisz kanał.</p><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otwórz Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Utwórz aplikację</span></span>
<span class="line"><span>-&gt; Dodaj https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Potwierdź uprawnienia Yandex Disk</span></span>
<span class="line"><span>-&gt; Skopiuj Client ID i Client Secret</span></span>
<span class="line"><span>-&gt; Wpisz Client ID / Client Secret w ImgBed</span></span>
<span class="line"><span>-&gt; Kliknij Get Token</span></span>
<span class="line"><span>-&gt; Skopiuj Refresh Token ze strony callback</span></span>
<span class="line"><span>-&gt; Wklej go z powrotem w ImgBed i zapisz</span></span></code></pre></div><h2 id="referencje" tabindex="-1">Referencje <a class="header-anchor" href="#referencje" aria-label="Permalink to &quot;Referencje&quot;">​</a></h2><ol><li>Rejestracja aplikacji Yandex: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Pobranie authorization code przez URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Endpoint tokenu OAuth Yandex: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const g=n(s,[["render",c]]);export{y as __pageData,g as default};
